{"expression": "// Try to find the latest observation value and date on the FRED page
const elements = document.querySelectorAll('.series-meta-observation-value, .series-meta-observation-date');
const results = [];
elements.forEach(el => results.push(el.textContent.trim()));

// Also try to find any data tables or recent values
const allText = document.body.innerText;
const match = allText.match(/(\d{4}-\d{2}-\d{2}):\s*([\d.]+)/g);
const latestMatch = allText.match(/Latest\s+observation.*?(\d{4}-\d{2}-\d{2}).*?([\d.]+)/s);

JSON.stringify({
  metaElements: results,
  dateValueMatches: match ? match.slice(-10) : null,
  latestObservation: latestMatch ? [latestMatch[1], latestMatch[2]] : null
});"}

